class Solution:
    def minOperations(self, nums):
        n = len(nums)
        seen = set()
        boundary = 0
        for i in range(n - 1, -1, -1):
            if nums[i] in seen:
                boundary = i + 1
                break
            seen.add(nums[i])
        return (boundary + 2) // 3

