var minOperations = function(nums) {
    const n = nums.length;
    const seen = new Set();
    let boundary = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (seen.has(nums[i])) {
            boundary = i + 1;
            break;
        }
        seen.add(nums[i]);
    }
    return Math.floor((boundary + 2) / 3);
};
